  ('social-worker-moex-00102', 'social-worker', 'social-worker-moex-114-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關個案工作者的倫理價值與決策之敘述，下列何者錯誤？', '["個案工作者的倫理價值系統既獨立運作，又同時受到外部環境的影響", "個案工作者在倫理決策過程中，需考量服務對象的動機、方法、目的及其影響", "個案工作者的倫理決策需聚焦於對服務對象之承諾，不會涉及不同系統的利害關係人", "個案工作者決策時，需檢視個人的、社會的、機構的、服務對象的，以及專業的相關價值"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "f49f57383162", "answer_pdf_sha1": "2baead120889", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
